allow:
Bash(powershell -Command "
\\$css = Get-Content '/tmp/fonts-latin.css' -Raw
\\$blocks = [regex]::Matches\(\\$css, '@font-face\\s*\\{\([^}]+\)\\}'\)
foreach \(\\$b in \\$blocks\) {
    \\$text = \\$b.Groups[1].Value
    if \(\\$text -match \\"font-family:\\s*'\([^']+\)'\\"\) { \\$fam = \\$Matches[1] } else { continue }
    if \(\\$text -match 'font-weight:\\s*\(\\d+\)'\)        { \\$wt  = \\$Matches[1] } else { continue }
    if \(\\$text -match 'url\\\(\(https://[^\)]+\\.woff2\)\\\)'\){ \\$url = \\$Matches[1] } else { continue }
    if \(\\$text -match 'U\\+0000-00FF'\) {
        Write-Host \\"\\$fam|\\$wt|\\$url\\"
    }
}
")
